  lessonTitle: string
  backUrl: string
  courseSlug: string
  chapterSlug: string
  lessonSlug: string
  lessonId: string
  introDescription?: string | null
  introMedia?: MediaType | string | number | null
  mediaMap?: Record<string, MediaType>
}

export function ExercisesPager({
  exercises,
  lessonTitle,
  backUrl,
  courseSlug,
  chapterSlug,
  lessonSlug,
  lessonId,
  introDescription,
  introMedia,
  mediaMap,
