                  (block) => {
                    const { id, type, ...rest } = block
                    return { id, type, ...rest }
                  },
                ),
              },
            }}
            mediaMap={
              mediaMap as Record<
                string,
                {
                  id: string
                  url?: string | null
                  filename?: string
                  mimeType?: string
                  altText?: string
                }
              >
            }
            translationNamespace="courses"
            showMathTools={true}
          />
        }
      />
    )
  }

